const body = $input.first().json.body || $input.first().json;

const topic = body.topic || 'everyday';
const topicDesc = body.topic_desc || 'everyday life';
const level = body.level || 'A1';
const history = body.history || [];
const sessionCount = body.sessionCount || 0;

// Calcul du taux de reussite pour adapter la difficulte
const recent = history.slice(-6);
const correctRate = recent.length > 0
  ? recent.filter(h => h.correct === true).length / recent.length
  : 0.5;

let difficultyNote = 'Standard difficulty for this level. Sentences of 5-8 words.';
if (correctRate >= 0.8 && recent.length >= 4) {
  difficultyNote = 'Student repeats well. Use slightly longer sentences (8-10 words), slightly more complex vocabulary.';
} else if (correctRate <= 0.3 && recent.length >= 4) {
  difficultyNote = 'Student struggles. Use very short sentences (3-5 words), basic everyday words only.';
}

// Varier les types de shadowing
const shadowTypes = ['repeat', 'repeat', 'question_answer'];
const type = shadowTypes[sessionCount % shadowTypes.length];

const prompt = `You are an English pronunciation and speaking coach for a French adult beginner at level ${level}.
Generate ONE shadowing exercise.

Topic area: ${topicDesc}
Difficulty: ${difficultyNote}

${
  type === 'repeat'
    ? `Exercise type: SHADOWING — student listens then repeats the sentence.
Generate a short, natural English sentence to repeat out loud.
The sentence must be practical and useful in real life.`
    : `Exercise type: QUESTION/ANSWER — give a simple English question, student answers it out loud with a simple suggested answer.
The question and answer must both be very short and natural.`
}

Respond ONLY with this exact JSON structure, no markdown, no extra text:
{
  "type": "${type === 'repeat' ? 'shadowing' : 'qa'}",
  "sentence_en": "the English sentence or question to read aloud",
  "sentence_fr": "exact French translation so the student understands",
  "phonetic_tip": "one short French tip about pronunciation of a tricky word in this sentence (ex: 'morning se prononce MOR-nigne')",
  "expected_words": ["list", "of", "key", "words", "student", "must", "say"],
  ${type === 'question_answer' ? '"suggested_answer_en": "a simple suggested answer in English", "suggested_answer_fr": "French translation of the suggested answer",' : ''}
  "explanation_fr": "1 sentence in French: what this expression means or when to use it",
  "explanation_en": "same in English for TTS"
}`;

return [{ json: { prompt, type, level, topic, sessionCount } }];

const agentOutput = $input.first().json;
const raw = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

try {
  const clean = raw.replace(/```json|```/g, '').trim();
  const ex = JSON.parse(clean);

  const required = ['type', 'sentence_en', 'sentence_fr', 'expected_words', 'explanation_fr', 'explanation_en'];
  for (const field of required) {
    if (!ex[field]) throw new Error('Champ manquant : ' + field);
  }

  ex._valid = true;
  return [{ json: ex }];

} catch(e) {
  return [{ json: {
    type: 'shadowing',
    sentence_en: 'Good morning, how are you?',
    sentence_fr: 'Bonjour, comment allez-vous ?',
    phonetic_tip: 'morning se prononce MOR-nigne',
    expected_words: ['good', 'morning', 'how', 'are', 'you'],
    explanation_fr: 'Formule de salutation du matin, très utilisée au quotidien.',
    explanation_en: 'Standard morning greeting used every day.',
    _valid: false,
    _error: e.message,
    _raw: raw.substring(0, 200)
  }}];
}
